    finder: new PF.BiBreadthFirstFinder(),
    optimal: true
}, {
    name: 'BiDijkstra',
    finder: new PF.BiDijkstraFinder(),
    optimal: true
});

// finders NOT guaranteed to find the shortest path
pathTests({
    name: 'BiAStar',
    finder: new PF.BiAStarFinder(),
    optimal: false
}, {
