        var map = MAPS.sparse;

        it('should find a path', function() {
            var grid = buildGrid(map);
            var path = finder.findPath(map.startX, map.startY, map.endX, map.endY, grid);
            path.should.be.an.Array();
            path.length.should.be.above(0);
